                        // let's try returning it as an entry.
                        if let Some(e) = RefEntry::try_acquire(self, r) {
                            // Destroy the new node.
                            Node::finalize(node.as_raw() as *mut Node<K, V>);
                            self.hot_data.len.fetch_sub(1, Ordering::Relaxed);

                            return e;
